-- ================================================================
-- FERREIRA & SA — Script de Migracao CORRIGIDO v2
-- Correcao: escape de apostrofos usando '' (padrao SQL ANSI)
-- Abril/2026
-- ================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
SET sql_mode = 'NO_BACKSLASH_ESCAPES';

-- ================================================================
-- SECAO 1: DDL — TABELAS (CREATE IF NOT EXISTS)
-- ================================================================

CREATE TABLE IF NOT EXISTS usuarios (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome VARCHAR(100) NOT NULL,
  email VARCHAR(100) NOT NULL UNIQUE,
  senha_hash VARCHAR(255) NOT NULL,
  perfil ENUM('administrador','comercial','cx','operacional') NOT NULL,
  ativo TINYINT(1) DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS parceiros (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome VARCHAR(150) NOT NULL,
  oab VARCHAR(30), area VARCHAR(60),
  email VARCHAR(100), telefone VARCHAR(30),
  pct_honorarios DECIMAL(5,2), observacoes TEXT,
  ativo TINYINT(1) DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS clientes (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome_completo VARCHAR(200) NOT NULL,
  telefone VARCHAR(30), data_fechamento DATE,
  tipo_acao VARCHAR(100), valor_acao VARCHAR(80),
  vencimento_1a VARCHAR(30), forma_pagamento VARCHAR(50),
  responsavel VARCHAR(60), area_juridica VARCHAR(60),
  nome_pasta_drive VARCHAR(250), status_original VARCHAR(80),
  pendencias TEXT, cadastro_assas VARCHAR(10),
  mes_origem VARCHAR(40), pasta_drive_id VARCHAR(100),
  pasta_drive_url VARCHAR(500),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS kanban_cards (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT NOT NULL,
  kanban ENUM('comercial_cx','operacional') NOT NULL,
  coluna_atual VARCHAR(80) NOT NULL,
  coluna_anterior VARCHAR(80),
  tipo_especial ENUM('nenhum','previdenciario','parceria_trabalhista','parceria_criminal','parceria_civel') DEFAULT 'nenhum',
  parceiro_id INT, dt_movimentacao DATETIME DEFAULT CURRENT_TIMESTAMP,
  usuario_id INT, observacao TEXT,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS processos (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT,
  nome_pasta VARCHAR(250), numero_processo VARCHAR(50),
  vara_juizo VARCHAR(150), tipo_demanda VARCHAR(100),
  data_distribuicao DATE, data_cadastro DATE,
  executante VARCHAR(60), link_drive VARCHAR(500),
  observacoes TEXT, mes_origem VARCHAR(40),
  tipo_especial ENUM('nenhum','previdenciario','parceria_trabalhista','parceria_criminal','parceria_civel') DEFAULT 'nenhum',
  parceiro_id INT, usuario_id INT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS documentos_pendentes (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT NOT NULL, descricao VARCHAR(250) NOT NULL,
  solicitado_em DATETIME DEFAULT CURRENT_TIMESTAMP,
  solicitante_id INT, recebido_em DATETIME, receptor_id INT,
  status ENUM('pendente','recebido') DEFAULT 'pendente',
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS prazos_processuais (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT, numero_processo VARCHAR(50),
  descricao_acao VARCHAR(250), prazo_fatal DATE NOT NULL,
  alertado_em DATETIME, concluido TINYINT(1) DEFAULT 0,
  usuario_id INT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS oficios_enviados (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT, numero_processo VARCHAR(50),
  empregador VARCHAR(250), data_envio DATE,
  retorno_ar VARCHAR(100), cod_rastreio VARCHAR(100),
  plataforma VARCHAR(50), observacoes TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS alvaras (
  id INT AUTO_INCREMENT PRIMARY KEY,
  cliente_id INT, numero_processo VARCHAR(50),
  data_peticionamento DATE, valor DECIMAL(12,2),
  honorarios_pct DECIMAL(5,2), valor_honorarios DECIMAL(12,2),
  repasse_cliente DECIMAL(12,2), natureza VARCHAR(100),
  prazo_pagamento VARCHAR(50), observacoes TEXT, estado_uf VARCHAR(30),
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (cliente_id) REFERENCES clientes(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS log_auditoria (
  id INT AUTO_INCREMENT PRIMARY KEY,
  usuario_id INT, cliente_id INT, acao VARCHAR(100),
  kanban VARCHAR(30), coluna_origem VARCHAR(80),
  coluna_destino VARCHAR(80), gatilhos TEXT,
  ip_usuario VARCHAR(45), created_at DATETIME DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ================================================================
-- SECAO 2: CLIENTES (629 registros)
-- Escape: apostrofos usando '' (SQL ANSI, sem backslash)
-- ================================================================



























-- ================================================================
-- SECAO 3: KANBAN CARDS COMERCIAIS (via SELECT)
-- ================================================================

SELECT c.id, 'comercial_cx',
  CASE
    WHEN LOWER(c.status_original) LIKE '%pasta apta%' THEN 'pasta_apta'
    WHEN LOWER(c.status_original) LIKE '%cancel%'     THEN 'cancelado'
    WHEN LOWER(c.status_original) LIKE '%suspenso%'   THEN 'suspenso'
    WHEN LOWER(c.status_original) LIKE '%aguardando%' THEN 'reuniao_cobrando_docs'
    WHEN LOWER(c.status_original) LIKE '%desistiu%'   THEN 'cancelado'
    WHEN LOWER(c.status_original) LIKE '%demitid%'    THEN 'cancelado'
    ELSE 'elaboracao_procuracao'
  END,
  CONCAT('Importado ', NOW(), ' | status original: ', IFNULL(c.status_original,''))
FROM clientes c
WHERE NOT EXISTS (
  SELECT 1 FROM kanban_cards k
  WHERE k.cliente_id = c.id AND k.kanban = 'comercial_cx'
);

-- Cards operacional para pasta_apta
SELECT c.id, 'operacional', 'pasta_apta', 'Migrado — pasta apta na planilha comercial'
FROM clientes c
WHERE LOWER(c.status_original) LIKE '%pasta apta%'
  AND NOT EXISTS (
    SELECT 1 FROM kanban_cards k
    WHERE k.cliente_id = c.id AND k.kanban = 'operacional'
  );

