SELECT
  (SELECT c.id FROM clientes c WHERE c.nome_pasta_drive = p.nome_pasta ORDER BY c.id LIMIT 1),
  'operacional',
  IFNULL(p._kc, 'em_execucao'),
  p.tipo_especial,
  CONCAT('Importado ', NOW(), ' | mes: ', IFNULL(p.mes_origem,''))
FROM processos p
WHERE p._kc IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM kanban_cards k
    WHERE k.cliente_id = (SELECT c2.id FROM clientes c2 WHERE c2.nome_pasta_drive = p.nome_pasta LIMIT 1)
      AND k.kanban = 'operacional'
  );

-- Vincular processos aos clientes
UPDATE processos p
SET p.cliente_id = (
  SELECT c.id FROM clientes c
  WHERE c.nome_pasta_drive = p.nome_pasta
  ORDER BY c.id LIMIT 1
)
WHERE p.cliente_id IS NULL;

ALTER TABLE processos DROP COLUMN IF EXISTS _kc;

